import{_ as a,o as e,c as t,a1 as p}from"./chunks/framework.Clqesclh.js";const g=JSON.parse('{"title":"GitHub Pages + Octopress 搭博客","description":"","frontmatter":{"title":"GitHub Pages + Octopress 搭博客","date":"2015-01-04 14:51:02 +0800","recommend":false},"headers":[],"relativePath":"posts/create-blog.md","filePath":"posts/create-blog.md"}'),n={name:"posts/create-blog.md"};function i(o,s,l,c,r,d){return e(),t("div",null,[...s[0]||(s[0]=[p(`<p><a href="https://pages.github.com" target="_blank" rel="noreferrer">Github Pages</a> 可用来搭建静态网站，它提供了免费域名、空间、无限流量，并且在世界各地都有较好的访问速度。</p><p><a href="http://octopress.org" target="_blank" rel="noreferrer">Octopress</a> 是开源的静态博客系统，可用来为静态网站提供所需的 HTML。</p><h2 id="准备工作" tabindex="-1">准备工作 <a class="header-anchor" href="#准备工作" aria-label="Permalink to &quot;准备工作&quot;">​</a></h2><p>在 GitHub 上新建名为 yourname.github.io 的版本库，之后可通过 yourname.github.io 域名来访问博客，还需要有 git 和 ruby 环境，尽量使用 rvm 管理 ruby，可避免因权限导致的 gem install 失败问题，记得要设置某个版本为当前使用版本，最后还需要更改 ruby 源，可提高下载速度</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gem sources -a https://gems.ruby-china.com/ -r https://rubygems.org/</span></span>
<span class="line"><span>gem sources -l</span></span></code></pre></div><h2 id="octopress-环境搭建" tabindex="-1">Octopress 环境搭建 <a class="header-anchor" href="#octopress-环境搭建" aria-label="Permalink to &quot;Octopress 环境搭建&quot;">​</a></h2><p>安装 Octopress</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git clone git://github.com/imathis/octopress.git octopress</span></span></code></pre></div><p>安装所需依赖</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cd octopress</span></span>
<span class="line"><span>sudo gem install bundler</span></span>
<span class="line"><span>bundle install</span></span></code></pre></div><p>安装默认模板</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>rake install</span></span></code></pre></div><p>关联 GitHub Pages</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>rake setup_github_pages</span></span>
<span class="line"><span>git@github.com:yourname/yourname.github.io.git</span></span></code></pre></div><p>配置 <a href="http://octopress.org/docs/configuring" target="_blank" rel="noreferrer">Octopress</a> 时建议删除 HTML 和 CSS 中用不到的东西，可提高访问速度</p><h2 id="写博客并发布" tabindex="-1">写博客并发布 <a class="header-anchor" href="#写博客并发布" aria-label="Permalink to &quot;写博客并发布&quot;">​</a></h2><p>新建文章（博客存储为 markdown 文件，位于 \\octopress\\source\\_posts 目录下）</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>rake new_post[&quot;new_blog_title&quot;]</span></span></code></pre></div><p>生成静态网站</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>rake generate</span></span></code></pre></div><p>通过 <a href="http://localhost:4000" target="_blank" rel="noreferrer">http://localhost:4000</a> 预览静态网站，之后修改 markdown 后直接刷新即可</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>rake preview</span></span></code></pre></div><p>部署并将 Octopress 生成的 HTML 等文件提交到 gh-pages 分支</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>rake deploy</span></span></code></pre></div><p>将 Octopress 修改过的 markdown 等资源文件提交到 master 分支</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git add .</span></span>
<span class="line"><span>git commit -m &#39;your commit message&#39;</span></span>
<span class="line"><span>git push origin source</span></span></code></pre></div><p>如果希望多台电脑能够一起使用 Octopress，首先下载 master 分支到你的电脑上，然后再下载 gh-pages 分支到博客根目录下的 _deploy 文件夹，然后就可以正常使用了。</p>`,27)])])}const u=a(n,[["render",i]]);export{g as __pageData,u as default};
